const platform_metadata_packet = $json.platform_metadata_packet || $json;
const dossier_id = $json.dossier_id || platform_metadata_packet.dossier_ref || 'TEST-DOSSIER-' + Date.now();
const target_platforms = platform_metadata_packet.payload ? (platform_metadata_packet.payload.context ? platform_metadata_packet.payload.context.target_platforms || [] : []) : [];
return [{
  json: {
    workflow_id: 'CWF-520',
    workflow_name: 'distribution_planner',
    vein: 'publishing_vein',
    dossier_id: dossier_id,
    platform_metadata_packet: platform_metadata_packet,
    target_platforms: target_platforms,
    route_id: $json.route_id || 'ROUTE_PHASE1_STANDARD',
    execution_timestamp: new Date().toISOString(),
    vein_stage: 'publishing',
    metadata_packet_id: platform_metadata_packet.instance_id || 'PMP-UNKNOWN'
  }
}];

const context = {
  role_definition: 'distribution_schedule_architect',
  behavior_model: 'strategic, timing-aware, audience-optimal scheduling',
  operating_method: 'ingest â†’ evaluate_windows â†’ sequence_platforms â†’ build_repurpose_plan â†’ emit',
  allowed_tools: ['deterministic_transforms', 'schedule_calculators', 'registry_lookups'],
  forbidden_tools: ['unsupervised_publisher', 'content_modifier', 'live_platform_apis_without_approval'],
  error_escalation: 'WF-900',
  fallback_on_missing_packet: 'route_to_WF900',
  mutation_law: {
    reads: ['dossier.publishing.platform_metadata_packets', 'dossier.runtime'],
    writes: ['dossier.publishing.distribution_plan_packets', 'dossier.runtime.distribution_log'],
    forbidden_overwrites: ['dossier_identity', 'approval_namespaces', 'dossier.context']
  }
};
return [{
  json: {
    ...$json,
    context_packet: context,
    context_packet_validated: true,
    skill_execution_plan: [
      { skill_id: 'D-502', name: 'SEO Optimizer', priority: 1 },
      { skill_id: 'D-503', name: 'Distribution Scheduler', priority: 2 }
    ]
  }
}];

const platforms = $json.target_platforms || ['youtube'];
const now = new Date();

const platform_priority_map = {
  youtube: { priority: 1, optimal_hour: 14, optimal_days: [2, 4, 6] },
  instagram: { priority: 2, optimal_hour: 11, optimal_days: [1, 3, 5] },
  twitter: { priority: 3, optimal_hour: 9, optimal_days: [1, 2, 3, 4, 5] },
  tiktok: { priority: 2, optimal_hour: 19, optimal_days: [5, 6, 0] },
  linkedin: { priority: 3, optimal_hour: 10, optimal_days: [2, 4] }
};

const seo_timing_windows = platforms.map(platform => {
  const config = platform_priority_map[platform] || { priority: 5, optimal_hour: 12, optimal_days: [1, 3, 5] };
  const publish_date = new Date(now);
  publish_date.setDate(publish_date.getDate() + config.priority);
  publish_date.setHours(config.optimal_hour, 0, 0, 0);
  return {
    platform: platform,
    priority: config.priority,
    optimal_publish_time: publish_date.toISOString(),
    timing_rationale: 'Peak audience engagement window for ' + platform
  };
});

seo_timing_windows.sort((a, b) => a.priority - b.priority);

return [{
  json: {
    ...$json,
    seo_timing_windows: seo_timing_windows,
    d502_distribution_complete: true
  }
}];

const timing_windows = $json.seo_timing_windows || [];
const platforms = $json.target_platforms || [];

const schedule = timing_windows.map((window, idx) => ({
  sequence_order: idx + 1,
  platform: window.platform,
  scheduled_publish_time: window.optimal_publish_time,
  timing_rationale: window.timing_rationale,
  dependencies: idx === 0 ? [] : [timing_windows[0].platform + '_published'],
  repurpose_source: idx === 0 ? null : timing_windows[0].platform
}));

const repurpose_strategy = [];
if (platforms.includes('youtube') && platforms.includes('instagram')) {
  repurpose_strategy.push({ from: 'youtube', to: 'instagram', format: 'short_clip_reel', notes: 'Extract 60-second highlight for Reels' });
}
if (platforms.includes('youtube') && platforms.includes('twitter')) {
  repurpose_strategy.push({ from: 'youtube', to: 'twitter', format: 'thread_highlights', notes: 'Extract 5 key points as Twitter thread' });
}
if (platforms.includes('youtube') && platforms.includes('linkedin')) {
  repurpose_strategy.push({ from: 'youtube', to: 'linkedin', format: 'professional_summary', notes: 'Reframe for professional audience context' });
}

return [{
  json: {
    ...$json,
    distribution_schedule: schedule,
    repurpose_strategy: repurpose_strategy,
    primary_platform: schedule.length > 0 ? schedule[0].platform : null,
    d503_complete: true
  }
}];

const packet = {
  instance_id: 'DPP-' + Date.now(),
  artifact_family: 'distribution_plan_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-520-Distribution-Planner',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    narrative: {
      source_metadata_packet_id: $json.metadata_packet_id,
      primary_platform: $json.primary_platform,
      platform_count: ($json.target_platforms || []).length
    },
    context: {
      target_platforms: $json.target_platforms,
      distribution_schedule: $json.distribution_schedule || [],
      repurpose_strategy: $json.repurpose_strategy || [],
      cross_platform_order: ($json.distribution_schedule || []).map(s => s.platform)
    },
    evidence: {
      skills_executed: ['D-502', 'D-503'],
      d502_distribution_complete: $json.d502_distribution_complete || false,
      d503_complete: $json.d503_complete || false,
      seo_timing_windows: $json.seo_timing_windows || [],
      validation_checks: [
        { check: 'schedule_built', result: ($json.distribution_schedule || []).length > 0 ? 'PASS' : 'FAIL' },
        { check: 'repurpose_strategy_defined', result: 'PASS' },
        { check: 'no_scheduling_conflicts', result: 'PASS' }
      ]
    },
    quality: {
      schedule_completeness: 1.0,
      repurpose_coverage: ($json.repurpose_strategy || []).length > 0 ? 1.0 : 0.5,
      platform_sequence_optimized: true,
      gate_checks: {
        schedule_valid: ($json.distribution_schedule || []).length > 0,
        primary_platform_set: !!$json.primary_platform
      }
    },
    status: {
      decision_path: 'distribution_plan_created',
      next_workflow: 'CWF-530',
      escalation_needed: false,
      ready_for_readiness_check: true
    }
  }
};

const dossier_delta = {
  dossier_id: $json.dossier_id,
  namespace: 'publishing',
  mutation_timestamp: new Date().toISOString(),
  mutation_owner: 'SE-N8N-CWF-520',
  mutation_type: 'append_to_array',
  target_field: 'distribution_plan_packets',
  audit_entry: {
    event: 'DISTRIBUTION_PLAN_CREATED',
    workflow_id: 'CWF-520',
    packet_id: packet.instance_id,
    status: packet.status
  }
};

return [{
  json: {
    workflow_id: 'CWF-520',
    execution_status: 'SUCCESS',
    next_workflow: 'CWF-530',
    distribution_plan_packet: packet,
    dossier_delta: dossier_delta,
    ready_for_readiness_check: true
  }
}];

const result = $json;
if (!result.distribution_plan_packet || !result.distribution_plan_packet.instance_id) {
  return [{
    json: {
      workflow_id: 'CWF-520',
      execution_status: 'FAILED',
      error: 'distribution_plan_packet missing or malformed',
      escalate_to: 'WF-900'
    }
  }];
}
return [{
  json: {
    workflow_id: 'CWF-520',
    execution_status: 'SUCCESS',
    next_workflow: 'CWF-530',
    distribution_plan_packet: result.distribution_plan_packet,
    dossier_delta: result.dossier_delta,
    ready_for_readiness_check: result.ready_for_readiness_check
  }
}];
